const AnnonceCard = ({ annonce, onSave }) => (
  <div className="bg-white rounded-xl shadow p-4 space-y-2">
    <h3 className="font-semibold">{annonce.titre}</h3>
    <p>{annonce.zone} - {annonce.type_bien} ({annonce.type_offre})</p>
    <p className="text-primary font-bold">{Number(annonce.prix || 0).toLocaleString()} FCFA</p>
    <button onClick={() => onSave?.(annonce.id)} className="bg-primary text-white px-3 py-1 rounded">Sauvegarder</button>
  </div>
);

export default AnnonceCard;
